        </Space>
      ),
    },
  ];

  const newsletterColumns: TableProps<NewsletterItem>["columns"] = [
    { title: "Mã", dataIndex: "maDangKy", width: 80, render: (value) => <Text strong>#{value}</Text> },
    { title: "Email", dataIndex: "email", render: (value) => <Text strong>{value}</Text> },
