          <Form.Item name="icon" label="Icon"><Input placeholder="Tent, Sparkles, Scissors..." /></Form.Item>
          <Form.Item name="gradient" label="Gradient"><Input placeholder="from-blue-500 to-cyan-400" /></Form.Item>
