          <Form.Item name="trangThai" label="Trạng thái"><Select options={[{ label: "Đang bật", value: 1 }, { label: "Đang tắt", value: 0 }]} /></Form.Item>
        </Form>
      </Modal>
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
