type FlightDetailData = {
  hangHangKhong?: string;
  soHieuChuyenBay?: string;
  hangVe?: string;
  goiGia?: string;
  diemKhoiHanh?: string;
  maSanBayDi?: string;
  tenSanBayDi?: string;
  diemDen?: string;
  maSanBayDen?: string;
  tenSanBayDen?: string;
  thoiGianKhoiHanh?: string;
  thoiGianDen?: string;
  hanhLyXachTay?: string;
  hanhLyKyGui?: string;
